arguments.file_text:
@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex justify-content-between list-unstyled mb-0 position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep && !isCompleted;
            var canClick = isCompleted && !isCurrent;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClicked(step, canClick)"
                role="button"
                tabindex="@(canClick ? 0 : -1)"
                aria-current="@(isCurrent ? "step" : null)">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="step-label @(isFuture ? "text-muted" : "")">@StepNames[i]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter]
    public EventCallback<int> OnStepSelected { get; set; }

    private async Task OnStepClicked(int step, bool canClick)
    {
        if (canClick)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
    z-index: 1;
    cursor: default;
}

.step-item.completed:not(.active) {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-item.completed:not(.active) .step-circle {
    font-size: 1rem;
}

.step-label {
    display: block;
    font-size: 0.75rem;
    white-space: nowrap;
}

.step-item.active .step-label {
    font-weight: 600;
}

/* Connector lines between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Company" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Title" @bind:event="oninput" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent"
                           @onclick="HandleCurrentToggle" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="Entry.Description" @bind:event="oninput"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public WorkEntryModel Entry { get; set; } = default!;

    [Parameter]
    public int Index { get; set; }

    [Parameter]
    public bool ShowRemove { get; set; }

    [Parameter]
    public EventCallback OnRemove { get; set; }

    private void HandleCurrentToggle()
    {
        if (!Entry.IsCurrent)
        {
            Entry.EndDate = null;
        }
    }
}

@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply
@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(validationErrors.ContainsKey("FullName") ? "is-invalid" : "")"
               @bind="Model.FullName" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("FullName"))
        {
            <div class="invalid-feedback">@validationErrors["FullName"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(validationErrors.ContainsKey("Email") ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("Email"))
        {
            <div class="invalid-feedback">@validationErrors["Email"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control @(validationErrors.ContainsKey("Phone") ? "is-invalid" : "")"
               @bind="Model.Phone" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("Phone"))
        {
            <div class="invalid-feedback">@validationErrors["Phone"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(validationErrors.ContainsKey("Address") ? "is-invalid" : "")"
               @bind="Model.Address" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("Address"))
        {
            <div class="invalid-feedback">@validationErrors["Address"]</div>
        }
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating...</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private Dictionary<string, string> validationErrors = new();
    private string? errorMessage;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationErrors.Clear();
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
            validationErrors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            validationErrors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            validationErrors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            validationErrors["Address"] = "Address is required.";

        if (validationErrors.Count > 0)
            return;

        isValidating = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isEmailValid)
            {
                validationErrors["Email"] = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        catch
        {
            errorMessage = "An error occurred while validating. Please try again.";
        }
        finally
        {
            isValidating = false;
        }
    }
}

