@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              OnNext="() => CompleteAndAdvance(1)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => CompleteAndAdvance(2)"
                             OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="() => CompleteAndAdvance(3)"
                            OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="() => CompleteAndAdvance(4)"
                             OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnBack="() => GoToStep(4)"
                        OnEditSection="GoToStep" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void CompleteAndAdvance(int step)
    {
        completedSteps.Add(step);
        currentStep = step + 1;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }
}

@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex justify-content-between list-unstyled mb-0 position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep && !isCompleted;
            var canClick = isCompleted && !isCurrent;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClicked(step, canClick)"
                role="button"
                tabindex="@(canClick ? 0 : -1)"
                aria-current="@(isCurrent ? "step" : null)">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="step-label @(isFuture ? "text-muted" : "")">@StepNames[i]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter]
    public EventCallback<int> OnStepSelected { get; set; }

    private async Task OnStepClicked(int step, bool canClick)
    {
        if (canClick)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
    z-index: 1;
    cursor: default;
}

.step-item.completed:not(.active) {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-item.completed:not(.active) .step-circle {
    font-size: 1rem;
}

.step-label {
    display: block;
    font-size: 0.75rem;
    white-space: nowrap;
}

.step-item.active .step-label {
    font-weight: 600;
}

/* Connector lines between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

