@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Personal { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter]
    public string CoverLetter { get; set; } = "";

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback<int> OnEditSection { get; set; }

    private bool isSubmitting;
    private bool isSubmitted;
    private int applicationId;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var personalInfo = new PersonalInfo(Personal.FullName, Personal.Email, Personal.Phone, Personal.Address);

            var workEntries = WorkEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate ?? DateTime.MinValue, e.IsCurrent ? null : e.EndDate, e.Description))
                .ToList();

            var references = References.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone))
                .ToList();

            var application = new JobApplication(personalInfo, new WorkHistory(workEntries), references, CoverLetter);
            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch
        {
            errorMessage = "An error occurred while submitting your application. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

