.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
    z-index: 1;
    cursor: default;
}

.step-item.completed:not(.active) {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-item.completed:not(.active) .step-circle {
    font-size: 1rem;
}

.step-label {
    display: block;
    font-size: 0.75rem;
    white-space: nowrap;
}

.step-item.active .step-label {
    font-weight: 600;
}

/* Connector lines between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

