@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Company" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Entry.Title" @bind:event="oninput" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent"
                           @onclick="HandleCurrentToggle" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="Entry.Description" @bind:event="oninput"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public WorkEntryModel Entry { get; set; } = default!;

    [Parameter]
    public int Index { get; set; }

    [Parameter]
    public bool ShowRemove { get; set; }

    [Parameter]
    public EventCallback OnRemove { get; set; }

    private void HandleCurrentToggle()
    {
        if (!Entry.IsCurrent)
        {
            Entry.EndDate = null;
        }
    }
}

@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply
@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(validationErrors.ContainsKey("FullName") ? "is-invalid" : "")"
               @bind="Model.FullName" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("FullName"))
        {
            <div class="invalid-feedback">@validationErrors["FullName"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(validationErrors.ContainsKey("Email") ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("Email"))
        {
            <div class="invalid-feedback">@validationErrors["Email"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control @(validationErrors.ContainsKey("Phone") ? "is-invalid" : "")"
               @bind="Model.Phone" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("Phone"))
        {
            <div class="invalid-feedback">@validationErrors["Phone"]</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(validationErrors.ContainsKey("Address") ? "is-invalid" : "")"
               @bind="Model.Address" @bind:event="oninput" />
        @if (validationErrors.ContainsKey("Address"))
        {
            <div class="invalid-feedback">@validationErrors["Address"]</div>
        }
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating...</span>
        }
        else
        {
            <span>Next</span>
        }
