@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply
@inject IApplicationService ApplicationService

<h4 class="mb-3">Review & Submit</h4>

@if (isSubmitted)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application has been received. Your application ID is <strong>#@applicationId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div class="fw-bold">@entry.Title at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                @foreach (var r in References)
                {
                    <div class="col-md-4 mb-2">
                        <div class="fw-bold">@r.Name</div>
                        <div class="small text-muted">@r.Relationship</div>
                        <div class="small">@r.Email</div>
                        <div class="small">@r.Phone</div>
                    </div>
                }
            </div>
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting...</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Personal { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter]
    public string CoverLetter { get; set; } = "";

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback<int> OnEditSection { get; set; }

    private bool isSubmitting;
    private bool isSubmitted;
    private int applicationId;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var personalInfo = new PersonalInfo(Personal.FullName, Personal.Email, Personal.Phone, Personal.Address);

            var workEntries = WorkEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate ?? DateTime.MinValue, e.IsCurrent ? null : e.EndDate, e.Description))
                .ToList();

            var references = References.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone))
                .ToList();

            var application = new JobApplication(personalInfo, new WorkHistory(workEntries), references, CoverLetter);
            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch
        {
            errorMessage = "An error occurred while submitting your application. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

@page "/apply"
@namespace sv_84fb4949c4e846cc9ce2ad7371882dca.Components.Pages.Apply
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              OnNext="() => CompleteAndAdvance(1)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => CompleteAndAdvance(2)"
                             OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="() => CompleteAndAdvance(3)"
                            OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="() => CompleteAndAdvance(4)"
                             OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnBack="() => GoToStep(4)"
                        OnEditSection="GoToStep" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void CompleteAndAdvance(int step)
    {
        completedSteps.Add(step);
        currentStep = step + 1;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }
}

